import{_ as s,o as e,c as i,ae as t}from"./chunks/framework.D6sYw4vw.js";const k=JSON.parse('{"title":"VScode中使用Git","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/91Tools/vscode_git.md","filePath":"zh/docs/91Tools/vscode_git.md","lastUpdated":1773144464000}'),p={name:"zh/docs/91Tools/vscode_git.md"};function o(n,a,d,h,l,r){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="vscode中使用git" tabindex="-1">VScode中使用Git <a class="header-anchor" href="#vscode中使用git" aria-label="Permalink to &quot;VScode中使用Git&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><pre><code>Contents：VScode,Git

Contributor: YJY

Email:522432938@qq.com

如有错误，请批评指正。
</code></pre></div><p>本篇介绍在vscode中使用git的方法(以码云为例，githup是同样的操作)</p><h2 id="初始化仓库" tabindex="-1">初始化仓库 <a class="header-anchor" href="#初始化仓库" aria-label="Permalink to &quot;初始化仓库&quot;">​</a></h2><p>如图所示，等价于git init</p><p>![在这里插入图片描述]</p><h2 id="生成公钥" tabindex="-1">生成公钥 <a class="header-anchor" href="#生成公钥" aria-label="Permalink to &quot;生成公钥&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">keygen </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t rsa </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">C </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxxxxx@qq.com&quot;</span></span></code></pre></div><p>一路回车，有y/n则y。在红框中的文件夹中去找公钥文件。</p><p>![在这里插入图片描述]</p><p><strong>id_rsa是私钥，id_rsa.pub是公钥</strong></p><p>![在这里插入图片描述]</p><p>使用公钥私钥匹配就可以免去登录验证</p><h2 id="配置公钥" tabindex="-1">配置公钥 <a class="header-anchor" href="#配置公钥" aria-label="Permalink to &quot;配置公钥&quot;">​</a></h2><p>githup与gitee是同样的方式，将id_rsa.pub的乱码复制到下图的地方。</p><p>![在这里插入图片描述]</p><h2 id="vscode中添加远程仓库" tabindex="-1">VScode中添加远程仓库 <a class="header-anchor" href="#vscode中添加远程仓库" aria-label="Permalink to &quot;VScode中添加远程仓库&quot;">​</a></h2><p>首先复制地址，选ssh</p><p>![在这里插入图片描述]</p><p>添加远程仓库</p><p>![在这里插入图片描述]</p><p>在框中输入复制过来的ssh地址，点击从URL添加远程仓库</p><p>![在这里插入图片描述]</p><p>输入仓库名字，指的是在vscode的仓库名字，随意填 ![在这里插入图片描述]</p><h2 id="提交与推送" tabindex="-1">提交与推送 <a class="header-anchor" href="#提交与推送" aria-label="Permalink to &quot;提交与推送&quot;">​</a></h2><p>先暂存更改</p><p>![在这里插入图片描述]</p><p>在...中可以进行一系列操作，本质上就是有一个图形化的git操作界面，</p><p>![在这里插入图片描述]</p><p>一般选择拉取自，或推送到</p><p>![在这里插入图片描述]</p>`,31)])])}const u=s(p,[["render",o]]);export{k as __pageData,u as default};
